import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.SAXException;

import java.io.IOException;
import java.io.InputStream;
import java.util.HashMap;
import java.util.Map;

public class XmlConfigParser {

    /**
     * Parses an XML configuration file from an InputStream and extracts
     * configuration settings into a Map.
     *
     * The XML is expected to have a structure like:
     * <configuration>
     *   <setting name="key1">value1</setting>
     *   <setting name="key2">value2</setting>
     * </configuration>
     *
     * @param inputStream the InputStream of the uploaded XML file
     * @return a Map containing configuration key-value pairs
     * @throws ParserConfigurationException if parser configuration fails
     * @throws IOException if an I/O error occurs
     * @throws SAXException if a parsing error occurs
     */
    public Map<String, String> parseConfiguration(InputStream inputStream)
            throws ParserConfigurationException, IOException, SAXException {

        Map<String, String> configMap = new HashMap<>();

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // SECURITY: Disable external entities and DTDs to prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(inputStream);
        document.getDocumentElement().normalize();

        NodeList settingNodes = document.getElementsByTagName("setting");

        for (int i = 0; i < settingNodes.getLength(); i++) {
            Node node = settingNodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                String name = element.getAttribute("name");
                String value = element.getTextContent().trim();
                if (name != null && !name.isEmpty()) {
                    configMap.put(name, value);
                }
            }
        }

        return configMap;
    }

    /**
     * Parses nested configuration sections into a Map where keys are
     * section.name formatted strings.
     *
     * Expected XML structure:
     * <configuration>
     *   <section name="database">
     *     <setting name="host">localhost</setting>
     *     <setting name="port">5432</setting>
     *   </section>
     *   <section name="cache">
     *     <setting name="enabled">true</setting>
     *   </section>
     * </configuration>
     *
     * @param inputStream the InputStream of the uploaded XML file
     * @return a Map containing configuration key-value pairs with section prefixes
     * @throws ParserConfigurationException if parser configuration fails
     * @throws IOException if an I/O error occurs
     * @throws SAXException if a parsing error occurs
     */
    public Map<String, String> parseNestedConfiguration(InputStream inputStream)
            throws ParserConfigurationException, IOException, SAXException {

        Map<String, String> configMap = new HashMap<>();

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // SECURITY: Disable external entities and DTDs to prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(inputStream);
        document.getDocumentElement().normalize();

        NodeList sectionNodes = document.getElementsByTagName("section");

        for (int i = 0; i < sectionNodes.getLength(); i++) {
            Node sectionNode = sectionNodes.item(i);
            if (sectionNode.getNodeType() == Node.ELEMENT_NODE) {
                Element sectionElement = (Element) sectionNode;
                String sectionName = sectionElement.getAttribute("name");

                NodeList settingNodes = sectionElement.getElementsByTagName("setting");
                for (int j = 0; j < settingNodes.getLength(); j++) {
                    Node settingNode = settingNodes.item(j);
                    if (settingNode.getNodeType() == Node.ELEMENT_NODE) {
                        Element settingElement = (Element) settingNode;
                        String settingName = settingElement.getAttribute("name");
                        String settingValue = settingElement.getTextContent().trim();

                        String key = (sectionName != null && !sectionName.isEmpty())
                                ? sectionName + "." + settingName
                                : settingName;

                        if (settingName != null && !settingName.isEmpty()) {
                            configMap.put(key, settingValue);
                        }
                    }
                }
            }
        }

        // Also pick up any top-level settings not inside a section
        Element root = document.getDocumentElement();
        NodeList rootChildren = root.getChildNodes();
        for (int i = 0; i < rootChildren.getLength(); i++) {
            Node child = rootChildren.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE && "setting".equals(child.getNodeName())) {
                Element settingElement = (Element) child;
                String name = settingElement.getAttribute("name");
                String value = settingElement.getTextContent().trim();
                if (name != null && !name.isEmpty()) {
                    configMap.put(name, value);
                }
            }
        }

        return configMap;
    }

    public static void main(String[] args) {
        XmlConfigParser parser = new XmlConfigParser();

        // Example usage with a sample XML from resources
        String sampleXml = "<configuration>" +
                "<setting name=\"app.name\">MyApp</setting>" +
                "<setting name=\"app.version\">1.0.0</setting>" +
                "<section name=\"database\">" +
                "  <setting name=\"host\">localhost</setting>" +
                "  <setting name=\"port\">5432</setting>" +
                "</section>" +
                "</configuration>";

        try {
            InputStream is = new java.io.ByteArrayInputStream(sampleXml.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            Map<String, String> config = parser.parseConfiguration(is);
            System.out.println("Flat configuration:");
            config.forEach((key, value) -> System.out.println("  " + key + " = " + value));

            is = new java.io.ByteArrayInputStream(sampleXml.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            Map<String, String> nestedConfig = parser.parseNestedConfiguration(is);
            System.out.println("\nNested configuration:");
            nestedConfig.forEach((key, value) -> System.out.println("  " + key + " = " + value));

        } catch (Exception e) {
            System.err.println("Error parsing XML configuration: " + e.getMessage());
            e.printStackTrace();
        }
    }
}